<template><section class="cas-content" :style="panelStyle"><div v-if="visible" class="cas-win97"><div class="cas-bar">Cas Content <span>{{ casIdDisplay }}</span></div><table><thead><tr><th v-for="h in tableHeaders" :key="h">{{ h }}</th></tr></thead><tbody><tr v-for="r in tableRows" :key="r.slot"><td>{{ r.slot }}</td><td @click="emit('cell-click',{slot:r.slot,jobName:r.jobName,event:$event})">{{ r.jobName }}</td></tr></tbody></table></div></section></template>
